import{_ as e,o as s,c as r,a2 as i}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Refactorizacion hacia Clean Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/11-refactorizacion-hacia-clean-architecture.md","filePath":"full-stack/arquitectura/clean-architecture/11-refactorizacion-hacia-clean-architecture.md","lastUpdated":1782521464000}'),o={name:"full-stack/arquitectura/clean-architecture/11-refactorizacion-hacia-clean-architecture.md"};function c(t,a,n,l,p,u){return s(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="refactorizacion-hacia-clean-architecture" tabindex="-1">Refactorizacion hacia Clean Architecture <a class="header-anchor" href="#refactorizacion-hacia-clean-architecture" aria-label="Permalink to &quot;Refactorizacion hacia Clean Architecture&quot;">​</a></h1><p>No hace falta reescribir una aplicacion para acercarla a Clean Architecture. Lo mas seguro suele ser refactorizar por flujos.</p><h2 id="paso-1-elegir-un-caso-real" tabindex="-1">Paso 1: elegir un caso real <a class="header-anchor" href="#paso-1-elegir-un-caso-real" aria-label="Permalink to &quot;Paso 1: elegir un caso real&quot;">​</a></h2><p>Escoge una funcionalidad con reglas claras:</p><ul><li>checkout.</li><li>registro de usuario.</li><li>generacion de factura.</li><li>aprobacion de solicitud.</li><li>publicacion de contenido.</li></ul><p>Evita empezar por toda la aplicacion.</p><h2 id="paso-2-extraer-el-caso-de-uso" tabindex="-1">Paso 2: extraer el caso de uso <a class="header-anchor" href="#paso-2-extraer-el-caso-de-uso" aria-label="Permalink to &quot;Paso 2: extraer el caso de uso&quot;">​</a></h2><p>Antes:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller:</span></span>
<span class="line"><span>  valida</span></span>
<span class="line"><span>  consulta DB</span></span>
<span class="line"><span>  calcula</span></span>
<span class="line"><span>  guarda</span></span>
<span class="line"><span>  responde</span></span></code></pre></div><p>Despues:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller:</span></span>
<span class="line"><span>  crea command</span></span>
<span class="line"><span>  ejecuta use case</span></span>
<span class="line"><span>  responde</span></span></code></pre></div><h2 id="paso-3-aislar-reglas" tabindex="-1">Paso 3: aislar reglas <a class="header-anchor" href="#paso-3-aislar-reglas" aria-label="Permalink to &quot;Paso 3: aislar reglas&quot;">​</a></h2><p>Mueve reglas que no son HTTP ni SQL hacia entidades o servicios de dominio.</p><h2 id="paso-4-crear-puertos-necesarios" tabindex="-1">Paso 4: crear puertos necesarios <a class="header-anchor" href="#paso-4-crear-puertos-necesarios" aria-label="Permalink to &quot;Paso 4: crear puertos necesarios&quot;">​</a></h2><p>Solo crea puertos para dependencias que el caso de uso necesita controlar:</p><ul><li>repositorio.</li><li>email gateway.</li><li>payment gateway.</li><li>event bus.</li><li>clock.</li></ul><h2 id="paso-5-cubrir-con-tests" tabindex="-1">Paso 5: cubrir con tests <a class="header-anchor" href="#paso-5-cubrir-con-tests" aria-label="Permalink to &quot;Paso 5: cubrir con tests&quot;">​</a></h2><p>Primero tests del caso de uso. Despues tests de adaptadores. Finalmente E2E del flujo completo.</p><h2 id="paso-6-repetir" tabindex="-1">Paso 6: repetir <a class="header-anchor" href="#paso-6-repetir" aria-label="Permalink to &quot;Paso 6: repetir&quot;">​</a></h2><p>La arquitectura emerge flujo a flujo. Si intentas migrar todo de golpe, el riesgo sube mucho.</p><h2 id="indicadores-de-avance" tabindex="-1">Indicadores de avance <a class="header-anchor" href="#indicadores-de-avance" aria-label="Permalink to &quot;Indicadores de avance&quot;">​</a></h2><ul><li>Menos logica en controladores.</li><li>Tests mas rapidos.</li><li>Errores de negocio mas claros.</li><li>Dependencias externas mas aisladas.</li><li>Cambios de infraestructura con menor impacto.</li></ul>`,22)])])}const m=e(o,[["render",c]]);export{h as __pageData,m as default};
